### `LruTtlCache.java`

```java
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.locks.ReentrantLock;

public class LruTtlCache<K, V> {

    public enum EvictionReason {
        EXPIRED,
        SIZE,
        REPLACED,
        MANUAL
    }

    @FunctionalInterface
    public interface EvictionListener<K, V> {
        void onEvict(K key, V value, EvictionReason reason);
    }

    public static final class Stats {
        private final long hits;
        private final long misses;
        private final long evictions;

        public Stats(long hits, long misses, long evictions) {
            this.hits = hits;
            this.misses = misses;
            this.evictions = evictions;
        }

        public long getHits() {
            return hits;
        }

        public long getMisses() {
            return misses;
        }

        public long getEvictions() {
            return evictions;
        }

        @Override
        public String toString() {
            return "Stats{" +
                    "hits=" + hits +
                    ", misses=" + misses +
                    ", evictions=" + evictions +
                    '}';
        }
    }

    public interface Clock {
        long nowMillis();
    }

    public static final Clock SYSTEM_CLOCK = System::currentTimeMillis;

    private static final class Node<K, V> {
        K key;
        V value;
        long expireAtMillis;
        Node<K, V> prev;
        Node<K, V> next;

        Node(K key, V value, long expireAtMillis) {
            this.key = key;
            this.value = value;
            this.expireAtMillis = expireAtMillis;
        }
    }

    private final int maxSize;
    private final EvictionListener<K, V> evictionListener;
    private final Clock clock;

    private final Map<K, Node<K, V>> map;
    private final ReentrantLock lock = new ReentrantLock();

    private final AtomicLong hits = new AtomicLong();
    private final AtomicLong misses = new AtomicLong();
    private final AtomicLong evictions = new AtomicLong();

    private Node<K, V> head;
    private Node<K, V> tail;

    public LruTtlCache(int maxSize) {
        this(maxSize, null, SYSTEM_CLOCK);
    }

    public LruTtlCache(int maxSize, EvictionListener<K, V> evictionListener) {
        this(maxSize, evictionListener, SYSTEM_CLOCK);
    }

    public LruTtlCache(int maxSize, EvictionListener<K, V> evictionListener, Clock clock) {
        if (maxSize <= 0) {
            throw new IllegalArgumentException("maxSize must be > 0");
        }
        this.maxSize = maxSize;
        this.evictionListener = evictionListener;
        this.clock = Objects.requireNonNull(clock, "clock");
        this.map = new HashMap<>();
    }

    public void put(K key, V value, long ttlMillis) {
        Objects.requireNonNull(key, "key");
        Objects.requireNonNull(value, "value");
        if (ttlMillis < 0) {
            throw new IllegalArgumentException("ttlMillis must be >= 0");
        }

        long now = clock.nowMillis();
        long expireAt = computeExpireAt(now, ttlMillis);

        K callbackKey = null;
        V callbackValue = null;
        EvictionReason callbackReason = null;

        lock.lock();
        try {
            Node<K, V> existing = map.get(key);
            if (existing != null) {
                callbackKey = existing.key;
                callbackValue = existing.value;
                callbackReason = EvictionReason.REPLACED;

                existing.value = value;
                existing.expireAtMillis = expireAt;
                moveToHead(existing);
            } else {
                Node<K, V> node = new Node<>(key, value, expireAt);
                map.put(key, node);
                addToHead(node);
            }

            while (map.size() > maxSize) {
                Node<K, V> lru = tail;
                if (lru == null) {
                    break;
                }
                removeNode(lru);
                map.remove(lru.key);
                evictions.incrementAndGet();
                fireEvictionListener(lru.key, lru.value, EvictionReason.SIZE);
            }
        } finally {
            lock.unlock();
        }

        if (callbackReason != null) {
            fireEvictionListener(callbackKey, callbackValue, callbackReason);
        }
    }

    public V get(K key) {
        Objects.requireNonNull(key, "key");

        long now = clock.nowMillis();

        lock.lock();
        try {
            Node<K, V> node = map.get(key);
            if (node == null) {
                misses.incrementAndGet();
                return null;
            }

            if (isExpired(node, now)) {
                removeNode(node);
                map.remove(key);
                misses.incrementAndGet();
                evictions.incrementAndGet();
                fireEvictionListener(node.key, node.value, EvictionReason.EXPIRED);
                return null;
            }

            moveToHead(node);
            hits.incrementAndGet();
            return node.value;
        } finally {
            lock.unlock();
        }
    }

    public V remove(K key) {
        Objects.requireNonNull(key, "key");

        lock.lock();
        try {
            Node<K, V> node = map.remove(key);
            if (node == null) {
                return null;
            }
            removeNode(node);
            evictions.incrementAndGet();
            fireEvictionListener(node.key, node.value, EvictionReason.MANUAL);
            return node.value;
        } finally {
            lock.unlock();
        }
    }

    public boolean containsKey(K key) {
        return get(key) != null;
    }

    public int size() {
        lock.lock();
        try {
            return map.size();
        } finally {
            lock.unlock();
        }
    }

    public void clear() {
        lock.lock();
        try {
            Node<K, V> current = head;
            while (current != null) {
                Node<K, V> next = current.next;
                fireEvictionListener(current.key, current.value, EvictionReason.MANUAL);
                evictions.incrementAndGet();
                current = next;
            }
            map.clear();
            head = null;
            tail = null;
        } finally {
            lock.unlock();
        }
    }

    public Stats stats() {
        return new Stats(hits.get(), misses.get(), evictions.get());
    }

    private boolean isExpired(Node<K, V> node, long nowMillis) {
        return nowMillis >= node.expireAtMillis;
    }

    private long computeExpireAt(long now, long ttlMillis) {
        if (ttlMillis == Long.MAX_VALUE) {
            return Long.MAX_VALUE;
        }
        long expireAt = now + ttlMillis;
        if (expireAt < 0) {
            return Long.MAX_VALUE;
        }
        return expireAt;
    }

    private void addToHead(Node<K, V> node) {
        node.prev = null;
        node.next = head;

        if (head != null) {
            head.prev = node;
        }
        head = node;

        if (tail == null) {
            tail = node;
        }
    }

    private void moveToHead(Node<K, V> node) {
        if (node == head) {
            return;
        }
        removeNode(node);
        addToHead(node);
    }

    private void removeNode(Node<K, V> node) {
        if (node.prev != null) {
            node.prev.next = node.next;
        } else {
            head = node.next;
        }

        if (node.next != null) {
            node.next.prev = node.prev;
        } else {
            tail = node.prev;
        }

        node.prev = null;
        node.next = null;
    }

    private void fireEvictionListener(K key, V value, EvictionReason reason) {
        if (evictionListener != null) {
            evictionListener.onEvict(key, value, reason);
        }
    }
}
