**Here's a complete implementation of an LRU Cache with per-key TTL in Java:**

```java
import java.time.Duration;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.locks.ReentrantReadWriteLock;
import java.util.function.Consumer;

/**
 * Thread-safe LRU Cache with per-key TTL support.
 * Uses lazy expiration (checks on access).
 */
public class LRUCacheWithTTL<K, V> {

    private final int maxSize;
    private final Consumer<EvictionEvent<K, V>> evictionCallback;

    // Main data structures
    private final ConcurrentHashMap<K, CacheEntry<K, V>> cache;
    private final LinkedHashSet<K> accessOrder; // For O(1) LRU ordering

    private final ReentrantReadWriteLock lock = new ReentrantReadWriteLock(true);

    // Statistics
    private final AtomicLong hits = new AtomicLong(0);
    private final AtomicLong misses = new AtomicLong(0);
    private final AtomicLong evictions = new AtomicLong(0);

    public static class Builder<K, V> {
        private int maxSize = 1000;
        private Consumer<EvictionEvent<K, V>> evictionCallback = e -> {};

        public Builder<K, V> maxSize(int maxSize) {
            this.maxSize = maxSize;
            return this;
        }

        public Builder<K, V> evictionCallback(Consumer<EvictionEvent<K, V>> callback) {
            this.evictionCallback = callback;
            return this;
        }

        public LRUCacheWithTTL<K, V> build() {
            return new LRUCacheWithTTL<>(maxSize, evictionCallback);
        }
    }

    public static <K, V> Builder<K, V> builder() {
        return new Builder<>();
    }

    public LRUCacheWithTTL(int maxSize) {
        this(maxSize, e -> {});
    }

    public LRUCacheWithTTL(int maxSize, Consumer<EvictionEvent<K, V>> evictionCallback) {
        if (maxSize <= 0) {
            throw new IllegalArgumentException("Max size must be positive");
        }
        this.maxSize = maxSize;
        this.evictionCallback = Objects.requireNonNull(evictionCallback);
        this.cache = new ConcurrentHashMap<>(maxSize);
        this.accessOrder = new LinkedHashSet<>();
    }

    /**
     * Get value for key if it exists and hasn't expired
     */
    public Optional<V> get(K key) {
        lock.readLock().lock();
        try {
            CacheEntry<K, V> entry = cache.get(key);
            if (entry == null) {
                misses.incrementAndGet();
                return Optional.empty();
            }

            if (entry.isExpired()) {
                // Lazy expiration - remove expired entry
                lock.readLock().unlock();
                lock.writeLock().lock();
                try {
                    removeInternal(key, EvictionReason.EXPIRED);
                } finally {
                    lock.writeLock().unlock();
                    lock.readLock().lock();
                }
                misses.incrementAndGet();
                return Optional.empty();
            }

            // Move to most recently used
            updateAccessOrder(key);
            hits.incrementAndGet();
            return Optional.of(entry.value);

        } finally {
            lock.readLock().unlock();
        }
    }

    /**
     * Put value with specified TTL
     */
    public void put(K key, V value, Duration ttl) {
        if (key == null || value == null || ttl == null || ttl.isNegative() || ttl.isZero()) {
            throw new IllegalArgumentException("Key, value, and positive TTL are required");
        }

        lock.writeLock().lock();
        try {
            Instant expiryTime = Instant.now().plus(ttl);
            CacheEntry<K, V> entry = new CacheEntry<>(key, value, expiryTime);

            boolean wasPresent = cache.containsKey(key);

            if (wasPresent) {
                // Update existing entry
                cache.put(key, entry);
                accessOrder.remove(key);
            } else {
                // Check capacity
                if (cache.size() >= maxSize) {
                    evictLRU();
                }
                cache.put(key, entry);
            }

            accessOrder.add(key); // Most recently used

        } finally {
            lock.writeLock().unlock();
        }
    }

    /**
     * Put with default TTL (no expiration)
     */
    public void put(K key, V value) {
        put(key, value, Duration.ofDays(3650)); // ~10 years = effectively never expires
    }

    /**
     * Remove key from cache
     */
    public boolean remove(K key) {
        lock.writeLock().lock();
        try {
            return removeInternal(key, EvictionReason.EXPLICIT);
        } finally {
            lock.writeLock().unlock();
        }
    }

    private boolean removeInternal(K key, EvictionReason reason) {
        CacheEntry<K, V> entry = cache.remove(key);
        if (entry != null) {
            accessOrder.remove(key);
            evictions.incrementAndGet();
            evictionCallback.accept(new EvictionEvent<>(key, entry.value, reason, entry.expiryTime));
            return true;
        }
        return false;
    }

    private void evictLRU() {
        if (accessOrder.isEmpty()) return;

        Iterator<K> iterator = accessOrder.iterator();
        if (iterator.hasNext()) {
            K lruKey = iterator.next();
            removeInternal(lruKey, EvictionReason.CAPACITY);
        }
    }

    private void updateAccessOrder(K key) {
        accessOrder.remove(key);
        accessOrder.add(key);
    }

    /**
     * Check if key exists and is not expired
     */
    public boolean containsKey(K key) {
        lock.readLock().lock();
        try {
            CacheEntry<K, V> entry = cache.get(key);
            if (entry == null) {
                return false;
            }
            if (entry.isExpired()) {
                lock.readLock().unlock();
                lock.writeLock().lock();
                try {
                    removeInternal(key, EvictionReason.EXPIRED);
                } finally {
                    lock.writeLock().unlock();
                    lock.readLock().lock();
                }
                return false;
            }
            return true;
        } finally {
            lock.readLock().unlock();
        }
    }

    /**
     * Get current size (excluding expired entries)
     */
    public int size() {
        lock.readLock().lock();
        try {
            // Clean expired entries lazily during size check
            cleanExpired();
            return cache.size();
        } finally {
            lock.readLock().unlock();
        }
    }

    private void cleanExpired() {
        List<K> toRemove = new ArrayList<>();

        for (Map.Entry<K, CacheEntry<K, V>> entry : cache.entrySet()) {
            if (entry.getValue().isExpired()) {
                toRemove.add(entry.getKey());
            }
        }

        for (K key : toRemove) {
            removeInternal(key, EvictionReason.EXPIRED);
        }
    }

    public int getMaxSize() {
        return maxSize;
    }

    public long getHits() {
        return hits.get();
    }

    public long getMisses() {
        return misses.get();
    }

    public long getEvictions() {
        return evictions.get();
    }

    public double getHitRatio() {
        long total = hits.get() + misses.get();
        return total == 0 ? 0.0 : (double) hits.get() / total;
    }

    public void clear() {
        lock.writeLock().lock();
        try {
            cache.clear();
            accessOrder.clear();
        } finally {
            lock.writeLock().unlock();
        }
    }

    // Internal classes
    private static class CacheEntry<K, V> {
        final K key;
        final V value;
        final Instant expiryTime;

        CacheEntry(K key, V value, Instant expiryTime) {
            this.key = key;
            this.value = value;
            this.expiryTime = expiryTime;
        }

        boolean isExpired() {
            return Instant.now().isAfter(expiryTime);
        }
    }

    public static class EvictionEvent<K, V> {
        public final K key;
        public final V value;
        public final EvictionReason reason;
        public final Instant expiryTime;

        public EvictionEvent(K key, V value, EvictionReason reason, Instant expiryTime) {
            this.key = key;
            this.value = value;
            this.reason = reason;
            this.expiryTime = expiryTime;
        }
    }

    public enum EvictionReason {
        CAPACITY, EXPIRED, EXPLICIT
    }

    @Override
    public String toString() {
        return String.format("LRUCacheWithTTL[size=%d/%d, hits=%d, misses=%d, hitRatio=%.2f%%]",
                cache.size(), maxSize, hits.get(), misses.get(), getHitRatio() * 100);
    }
}
